        let (ptr, len, cap) = self.vec_ptr_len_cap_i8(&vec_value, args[0].span, fctx)?;
        let elem_size = self.vec_elem_size(&elem_ty, fctx);
        let needle_ptr = self.value_to_i8_ptr(&needle, fctx);
        let out_index_slot = self.new_temp();
